// E02S01 — Parse SMS Fields (duplicated here for standalone mode)
// In Option B (extending E02S01), this node is already present — skip this one.
const body = $('Webhook').item.json.body;
const messageBody = body.Body || '';
const fromPhone = body.From || '';
const toPhone = body.To || '';
return [{ json: { message_body: messageBody, from_phone: fromPhone, to_phone: toPhone } }];

// AC1: Extract tech name from dispatcher SMS reply
// Trim whitespace — ilike in Supabase handles case-insensitive matching server-side
const rawText = $('Parse SMS Fields').item.json.message_body || '';
const techName = rawText.trim();

if (!techName) {
  throw new Error('[E02S02] Empty message_body — no tech name to match');
}

return [{ json: { tech_name: techName } }];

// AC4: Build confirmation SMS for dispatcher
// Template: 'Job #[ID] assigned to [Tech Name].'
// Job # = last 6 chars of UUID, uppercased

const jobId = $('Get Latest New Job').item.json.id;
const jobShort = jobId.slice(-6).toUpperCase();
const techName = $('Get Tech by Name').item.json.name;
const dispatcherPhone = $('Parse SMS Fields').item.json.from_phone;
const fromNumber = $('Get Client by Phone').item.json.twilio_number;

if (!jobId) throw new Error('[E02S02] job ID missing in Build Confirmation SMS');
if (!techName) throw new Error('[E02S02] tech name missing in Build Confirmation SMS');
if (!dispatcherPhone) throw new Error('[E02S02] dispatcher phone missing in Build Confirmation SMS');
if (!fromNumber) throw new Error('[E02S02] from_number (twilio_number) missing in Build Confirmation SMS');

const confirmMsg = `Job #${jobShort} assigned to ${techName}.`;

return [{
  json: {
    confirmation_msg: confirmMsg,
    dispatcher_phone: dispatcherPhone,
    from_number: fromNumber
  }
}];
